import React, { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  //   const { isAdmin, logout } = useAuth();
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const navLinks = [
    { label: "Home", href: "/#home" },
    { label: "Tours", href: "/#tours" },
    { label: "About", href: "/#about" },
    { label: "Contact", href: "/#contact" },
  ];

  const isHomePage = location.pathname === "/";

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 nav-blur ${
        scrolled || !isHomePage
          ? "bg-mountain-900/95 shadow-lg py-3"
          : "bg-transparent py-5"
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-3">
          {/* ↓ DROP YOUR logo.png INTO frontend/src/ AND REPLACE THE src BELOW */}
          {/* <img src="/logo.png" alt="Kumaon Soul Travels" className="h-10 w-auto" /> */}
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-gradient-to-br from-mountain-500 to-forest-700 rounded-lg flex items-center justify-center">
              <span className="text-white text-lg font-bold font-display">
                K
              </span>
            </div>
            <div className="flex flex-col leading-tight">
              <span className="text-white font-display font-semibold text-sm tracking-wide">
                Him Kiran
              </span>
              <span className="text-blue-200 text-xs tracking-widest uppercase">
                TOURS
              </span>
            </div>
          </div>
        </Link>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="text-white/80 hover:text-white text-sm font-medium tracking-wide transition-colors duration-200 hover:text-blue-300"
            >
              {link.label}
            </a>
          ))}
          {/* {isAdmin ? (
            <div className="flex items-center gap-3">
              <Link
                to="/admin"
                className="text-white/80 hover:text-white text-sm font-medium tracking-wide transition-colors"
              >
                Dashboard
              </Link>
              <button
                onClick={logout}
                className="text-xs bg-red-500/20 hover:bg-red-500/40 text-red-300 border border-red-500/30 px-3 py-1.5 rounded-full transition-colors"
              >
                Logout
              </button>
            </div>
          ) : (
            // <Link
            //   to="/admin/login"
            //   className="text-xs bg-white/10 hover:bg-white/20 text-white border border-white/20 px-4 py-2 rounded-full transition-all duration-200"
            // >
            //   Admin
            // </Link>
          )} */}
        </div>

        {/* Mobile hamburger */}
        <button
          className="md:hidden text-white p-2"
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
        >
          {menuOpen ? (
            <svg
              className="w-6 h-6"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          ) : (
            <svg
              className="w-6 h-6"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M4 6h16M4 12h16M4 18h16"
              />
            </svg>
          )}
        </button>
      </div>

      {/* Mobile menu */}
      {menuOpen && (
        <div className="md:hidden bg-mountain-900/98 border-t border-white/10 px-4 py-4 space-y-3">
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              onClick={() => setMenuOpen(false)}
              className="block text-white/80 hover:text-white py-2 text-sm font-medium"
            >
              {link.label}
            </a>
          ))}
          {/* <Link
            to="/admin/login"
            onClick={() => setMenuOpen(false)}
            className="block text-white/60 hover:text-white py-2 text-sm"
          >
            Admin Panel
          </Link> */}
        </div>
      )}
    </nav>
  );
};

export default Navbar;
